141	        // input for next layer
142	        inpL = cur;
143	    }
144	    cur = inpL;
145	
146	    cur = build_norm(cur,
147	            model.output_norm, NULL,
148	            LLM_NORM_RMS, -1);
149	
150	    cb(cur, "result_norm", -1);
