static common_chat_params common_chat_params_init_functionary_v3_2(
        const common_chat_template & tmpl,
        const autoparser::generation_params & inputs) {

    common_chat_params data;

    // 1. Render the template to get the initial prompt
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);

    // 2. Set the format (how to parse responses)
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    // 3. Tokens to preserve (won't be modified during generation)
    data.preserved_tokens = { ">>>all" };

    // 4. Detect if tools are present
    auto has_tools = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    // 5. Build the parser using PEG builder DSL
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto content_until_tool = p.literal("all\n") + p.content(p.until(">>>"));
        auto generation_prompt = p.literal(inputs.generation_prompt);

        // Build tool choice parser for each function
        auto tool_choice = p.choice();
        foreach_function(inputs.tools, [&](const json & tool) {
            const auto & function = tool.at("function");
            std::string name = function.at("name");
            const auto & schema = function.at("parameters");

            auto tool_parser = p.tool(
                p.tool_open(p.tool_name(p.literal(name)) + p.literal("\n")) +
                p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema))
            );
            tool_choice |= p.rule("tool-" + name, tool_parser);
        });

        // Return the parser structure
        return generation_prompt + content_until_end + p.end();
    });

    data.parser = parser.save();

    // 6. Build grammar constraints (if tools present)
    if (include_grammar) {
        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto schema = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        // 7. Set grammar triggers (when to start enforcing grammar)
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_PATTERN, ">>>(?!all)" }
        };
    }

    // 8. Optional: thinking support
    data.supports_thinking = true;
    data.thinking_start_tag = "[THINK]";
    data.thinking_end_tag = "[/THINK]";

    return data;
}
```

